---
import BaseLayout from '../../layouts/BaseLayout.astro';
import Hero from '../../components/Hero.astro';
import MinistryCard from '../../components/MinistryCard.astro';
import { getMinistries, urlForImage, type Ministry } from '../../lib/sanity';

const title = 'Community & Ministries | FICCC';
const description = 'Explore the ministries and community groups at First Ithaca Chinese Christian Church.';

let ministries: Ministry[] = [];

try {
  ministries = await getMinistries('en');
} catch {
  // Sanity unreachable — continue with empty array
}

const ministriesWithSlug = ministries.filter((m) => m.slug?.current);

// ---------- Fallback fellowship groups (from em.ficcc.org + cm.ficcc.org) ----------
const fallbackGroups = [
  {
    name: 'Discipleship Groups',
    meetingTime: 'Sundays 11:00 AM',
    description: 'Small groups for deeper Bible study and mutual encouragement after the Sunday gathering.',
  },
  {
    name: 'Midweek Bible Study',
    meetingTime: 'Thursdays 7:00 PM',
    description: 'A weekly evening study open to everyone — come dig into Scripture with us.',
  },
  {
    name: 'Youth Group',
    meetingTime: 'Fridays 7:30 PM',
    description: 'Fellowship and fun for middle and high school students.',
  },
  {
    name: 'Monthly Prayer Meeting',
    meetingTime: '1st Wednesday 7:30 PM',
    description: 'A monthly gathering to pray together for our church, community, and world.',
  },
  {
    name: 'Children\'s Sunday School',
    meetingTime: 'Sundays 11:15 AM',
    description: 'Age-appropriate Bible teaching and activities for kids during the Sunday School hour.',
  },
  {
    name: 'Adult Sunday School',
    meetingTime: 'Sundays 11:15 AM',
    description: 'Topical and book-by-book studies for adults of all backgrounds.',
  },
];
---

<BaseLayout title={title} description={description}>
  <main>
    <Hero
      title="Community & Ministries"
      subtitle="Get connected through our church ministries"
      backgroundImage="/images/hero-placeholder.svg"
    />

    {ministriesWithSlug.length > 0 ? (
      <section class="ministries-listing" aria-label="Ministries">
        <div class="ministries-listing__inner">
          <div class="ministries-grid">
            {ministriesWithSlug.map((ministry) => (
              <MinistryCard
                name={ministry.name}
                image={urlForImage(ministry.image, { width: 600 }) || undefined}
                meetingTime={ministry.meetingTime}
                slug={ministry.slug!.current}
              />
            ))}
          </div>
        </div>
      </section>
    ) : (
      <section class="ministries-listing" aria-label="Ministries and Groups">
        <div class="ministries-listing__inner">
          <p class="ministries-listing__intro">
            There are many ways to get connected at FICCC. Here are some of our regular gatherings and groups.
          </p>
          <div class="ministries-grid">
            {fallbackGroups.map((group) => (
              <div class="group-card">
                <h3 class="group-card__name">{group.name}</h3>
                {group.meetingTime && (
                  <p class="group-card__time">{group.meetingTime}</p>
                )}
                <p class="group-card__desc">{group.description}</p>
              </div>
            ))}
          </div>
        </div>
      </section>
    )}
  </main>
</BaseLayout>

<style>
  .ministries-listing {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-bg);
  }

  .ministries-listing__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .ministries-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: var(--space-8);
  }

  .ministries-listing__intro {
    font-family: var(--font-body);
    font-size: var(--text-lg);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
    text-align: center;
    max-width: 40rem;
    margin-inline: auto;
    margin-block-end: var(--space-10);
  }

  .group-card {
    background-color: var(--color-stone);
    border-radius: var(--radius-md);
    padding: var(--space-8) var(--space-6);
  }

  .group-card__name {
    font-family: var(--font-heading);
    font-size: var(--text-xl);
    color: var(--color-ink);
    margin-block-end: var(--space-2);
  }

  .group-card__time {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    font-weight: 600;
    color: var(--color-terracotta);
    margin-block-end: var(--space-3);
  }

  .group-card__desc {
    font-family: var(--font-body);
    font-size: var(--text-base);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
    margin: 0;
  }

  @media (max-width: 1024px) {
    .ministries-grid {
      grid-template-columns: repeat(2, 1fr);
    }
  }

  @media (max-width: 640px) {
    .ministries-grid {
      grid-template-columns: 1fr;
      gap: var(--space-6);
    }

    .ministries-listing {
      padding: var(--space-10) var(--space-4);
    }
  }
</style>

---
import BaseLayout from '../../layouts/BaseLayout.astro';
import Hero from '../../components/Hero.astro';
import {
  getMinistries,
  getMinistryBySlug,
  urlForImage,
  portableTextToHtml,
  type Ministry,
  type MinistryDetail,
} from '../../lib/sanity';

export async function getStaticPaths() {
  let ministries: Ministry[] = [];

  try {
    ministries = await getMinistries('en');
  } catch {
    // Sanity unreachable — return empty paths so build succeeds
  }

  return ministries
    .filter((m) => m.slug?.current)
    .map((ministry) => ({
      params: { slug: ministry.slug!.current },
    }));
}

const { slug } = Astro.params;

let ministry: MinistryDetail | null = null;

try {
  ministry = await getMinistryBySlug(slug!, 'en');
} catch {
  // Sanity unreachable — ministry stays null
}

if (!ministry) {
  return Astro.redirect('/ministries');
}

const descriptionHtml = portableTextToHtml(ministry.description);
const title = `${ministry.name} | Ministries | FICCC`;
const leaderPhoto = ministry.leader?.photo
  ? urlForImage(ministry.leader.photo, { width: 200 })
  : '';
---

<BaseLayout title={title}>
  <main>
    <Hero
      title={ministry.name}
      backgroundImage="/images/hero-placeholder.svg"
    />

    <article class="ministry-detail">
      <div class="ministry-detail__inner">
        <a class="ministry-detail__back" href="/ministries">← Back to Ministries</a>

        {ministry.leader?.name && (
          <section class="ministry-detail__leader" aria-label="Ministry leader">
            {leaderPhoto && (
              <img
                class="ministry-detail__leader-photo"
                src={leaderPhoto}
                alt={ministry.leader.name}
                loading="lazy"
                width="120"
                height="120"
              />
            )}
            <div class="ministry-detail__leader-info">
              <p class="ministry-detail__leader-name">{ministry.leader.name}</p>
              {ministry.leader.role && (
                <p class="ministry-detail__leader-role">{ministry.leader.role}</p>
              )}
            </div>
          </section>
        )}

        {ministry.meetingTime && (
          <div class="ministry-detail__meta">
            <span class="ministry-detail__label">Meeting Time</span>
            <span class="ministry-detail__value">{ministry.meetingTime}</span>
          </div>
        )}

        {descriptionHtml && (
          <div class="ministry-detail__description" set:html={descriptionHtml} />
        )}
      </div>
    </article>
  </main>
</BaseLayout>

<style>
  .ministry-detail {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-bg);
  }

  .ministry-detail__inner {
    max-width: 48rem;
    margin-inline: auto;
  }

  /* ---------- Back link ---------- */
  .ministry-detail__back {
    display: inline-block;
    font-family: var(--font-body);
    font-size: var(--text-sm);
    font-weight: 500;
    color: var(--color-terracotta);
    text-decoration: none;
    margin-block-end: var(--space-8);
    transition: color var(--transition);
  }

  .ministry-detail__back:hover {
    color: #b3654b;
  }

  .ministry-detail__back:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }

  /* ---------- Leader ---------- */
  .ministry-detail__leader {
    display: flex;
    align-items: center;
    gap: var(--space-6);
    margin-block-end: var(--space-8);
    padding: var(--space-6);
    background-color: var(--color-stone);
    border-radius: var(--radius-md);
  }

  .ministry-detail__leader-photo {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    object-fit: cover;
    flex-shrink: 0;
  }

  .ministry-detail__leader-info {
    display: flex;
    flex-direction: column;
    gap: var(--space-1);
  }

  .ministry-detail__leader-name {
    font-family: var(--font-heading);
    font-size: var(--text-lg);
    color: var(--color-ink);
    line-height: var(--leading-tight);
  }

  .ministry-detail__leader-role {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    color: var(--color-body);
    line-height: var(--leading-relaxed);
  }

  /* ---------- Meta ---------- */
  .ministry-detail__meta {
    display: flex;
    flex-direction: column;
    gap: var(--space-1);
    margin-block-end: var(--space-8);
    padding: var(--space-6);
    background-color: var(--color-stone);
    border-radius: var(--radius-md);
  }

  .ministry-detail__label {
    font-family: var(--font-body);
    font-size: var(--text-xs);
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: var(--color-body);
  }

  .ministry-detail__value {
    font-family: var(--font-body);
    font-size: var(--text-base);
    color: var(--color-ink);
  }

  /* ---------- Description ---------- */
  .ministry-detail__description {
    font-family: var(--font-body);
    font-size: var(--text-base);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
  }

  .ministry-detail__description :global(p) {
    margin-block-end: var(--space-4);
  }

  .ministry-detail__description :global(p:last-child) {
    margin-block-end: 0;
  }

  .ministry-detail__description :global(a) {
    color: var(--color-terracotta);
    text-decoration: underline;
  }

  /* ---------- Responsive ---------- */
  @media (max-width: 640px) {
    .ministry-detail {
      padding: var(--space-10) var(--space-4);
    }

    .ministry-detail__leader {
      flex-direction: column;
      text-align: center;
    }

    .ministry-detail__leader-info {
      align-items: center;
    }
  }
</style>

